476		std::string generate_device_function(const std::string& name) const override {
477			std::string density_network = name + "_density_network";
478			std::string rgb_network = name + "_rgb_network";
479			std::string pos_encoding = name + "_pos_encoding";
480			std::string dir_encoding = name + "_dir_encoding";
481	
482			std::ostringstream preamble;
483			preamble
484				<< m_density_network->generate_device_function(density_network) << "\n\n"
485				<< m_rgb_network->generate_device_function(rgb_network) << "\n\n"
486				<< m_pos_encoding->generate_device_function(pos_encoding) << "\n\n"
487				<< m_dir_encoding->generate_device_function(dir_encoding) << "\n\n"
488				;
489	
490			std::string body = dfmt(1, R"(
491					auto pos_enc_out = {POS_ENC}(input.slice<0, {POS_ENC_DIMS_IN}>(), params + {POS_ENC_PARAMS_OFFSET}, fwd_ctx ? fwd_ctx + WARP_SIZE * {POS_ENC_FWD_CTX_OFFSET} : nullptr);
492	
493					{RGB_MLP_IN} rgb_mlp_in;
494					rgb_mlp_in.slice<0, {DENSITY_MLP_DIMS_OUT}>() = {DENSITY_MLP}(pos_enc_out, params, fwd_ctx);
495					rgb_mlp_in.slice<{DENSITY_MLP_DIMS_OUT}, {DIR_ENC_DIMS_OUT}>() = {DIR_ENC}(input.slice<{DIR_OFFSET}, {DIR_ENC_DIMS_IN}>(), params + {DIR_ENC_PARAMS_OFFSET}, fwd_ctx ? fwd_ctx + WARP_SIZE * {DIR_ENC_FWD_CTX_OFFSET} : nullptr);
496	
497					auto rgb_mlp_out = {RGB_MLP}(rgb_mlp_in, params + {RGB_MLP_PARAMS_OFFSET}, fwd_ctx ? fwd_ctx + WARP_SIZE * {RGB_MLP_FWD_CTX_OFFSET} : nullptr);
498	
499					return {{rgb_mlp_out[0], rgb_mlp_out[1], rgb_mlp_out[2], rgb_mlp_in[0]}};
500				)",
501				"POS_ENC"_a = pos_encoding,
502				"POS_ENC_DIMS_IN"_a = m_pos_encoding->input_width(),
503				"POS_ENC_PARAMS_OFFSET"_a = m_density_network->n_params() + m_rgb_network->n_params(),
504				"POS_ENC_FWD_CTX_OFFSET"_a = m_density_network->device_function_fwd_ctx_bytes() + m_rgb_network->device_function_fwd_ctx_bytes(),
505				"RGB_MLP"_a = rgb_network,
506				"RGB_MLP_IN"_a = m_rgb_network->generate_vec_in(),
507				"RGB_MLP_PARAMS_OFFSET"_a = m_density_network->n_params(),
508				"RGB_MLP_FWD_CTX_OFFSET"_a = m_density_network->device_function_fwd_ctx_bytes(),
509				"DENSITY_MLP"_a = density_network,
510				"DENSITY_MLP_DIMS_OUT"_a = m_density_network->output_width(),
511				"DIR_ENC"_a = dir_encoding,
512				"DIR_ENC_DIMS_IN"_a = m_dir_encoding->input_width(),
513				"DIR_ENC_DIMS_OUT"_a = m_dir_encoding->output_width(),
514				"DIR_ENC_PARAMS_OFFSET"_a = m_density_network->n_params() + m_rgb_network->n_params() + m_pos_encoding->n_params(),
515				"DIR_ENC_FWD_CTX_OFFSET"_a = m_density_network->device_function_fwd_ctx_bytes() + m_rgb_network->device_function_fwd_ctx_bytes() + m_pos_encoding->device_function_fwd_ctx_bytes(),
516				"DIR_OFFSET"_a = m_dir_offset
517			);
518	
519			return fmt::format("{}{}", preamble.str(), this->generate_device_function_from_body(name, body));
520		}
521	
522		std::string generate_backward_device_function(const std::string& name, uint32_t n_threads) const override {
523			std::string density_network = name + "_density_network";
524			std::string rgb_network = name + "_rgb_network";
525			std::string pos_encoding = name + "_pos_encoding";
526			std::string dir_encoding = name + "_dir_encoding";
527	
528			std::ostringstream preamble;
529			preamble
530				<< m_density_network->generate_backward_device_function(density_network, n_threads) << "\n\n"
531				<< m_rgb_network->generate_backward_device_function(rgb_network, n_threads) << "\n\n"
532				<< m_pos_encoding->generate_backward_device_function(pos_encoding, n_threads) << "\n\n"
533				<< m_dir_encoding->generate_backward_device_function(dir_encoding, n_threads) << "\n\n"
534				;
535	
536			std::string body = dfmt(1, R"(
537					bool requires_pos_encoding_bwd = {POS_ENC_N_PARAMS} != 0 || dL_dx;
538					bool requires_dir_encoding_bwd = {DIR_ENC_N_PARAMS} != 0 || dL_dx;
539	
540					{RGB_MLP_IN} dL_drgb_mlp_in;
541					{RGB_MLP}(
542						{RGB_MLP_OUT}(dL_dy.rgb()),
543						params + {RGB_MLP_PARAMS_OFFSET},
544						fwd_ctx + WARP_SIZE * {RGB_MLP_FWD_CTX_OFFSET},
545						dL_dparams ? dL_dparams + {RGB_MLP_PARAMS_OFFSET} : nullptr,
546						&dL_drgb_mlp_in
547					);
548					dL_drgb_mlp_in[0] = dL_drgb_mlp_in[0] + dL_dy[3];
549	
550					if (requires_dir_encoding_bwd) {{
551						{DIR_ENC}(
552							dL_drgb_mlp_in.slice<{DENSITY_MLP_DIMS_OUT}, {DIR_ENC_DIMS_OUT}>(),
553							params + {DIR_ENC_PARAMS_OFFSET},
554							fwd_ctx + WARP_SIZE * {DIR_ENC_FWD_CTX_OFFSET},
555							dL_dparams ? dL_dparams + {DIR_ENC_PARAMS_OFFSET} : nullptr,
556							dL_dx ? &dL_dx->slice<{DIR_OFFSET}, {DIR_ENC_DIMS_IN}>() : nullptr
557						);
558					}}
559	
560					{POS_ENC_OUT} dL_dpos_enc_out;
561					{DENSITY_MLP}(
562						dL_drgb_mlp_in.slice<0, {DENSITY_MLP_DIMS_OUT}>(),
563						params,
564						fwd_ctx,
565						dL_dparams,
566						requires_pos_encoding_bwd ? &dL_dpos_enc_out : nullptr
567					);
568	
569					if (requires_pos_encoding_bwd) {{
570						{POS_ENC}(
571							dL_dpos_enc_out,
572							params + {POS_ENC_PARAMS_OFFSET},
573							fwd_ctx + WARP_SIZE * {POS_ENC_FWD_CTX_OFFSET},
574							dL_dparams ? dL_dparams + {POS_ENC_PARAMS_OFFSET} : nullptr,
575							dL_dx ? &dL_dx->slice<0, {POS_ENC_DIMS_IN}>() : nullptr
576						);
577					}}
578				)",
579				"POS_ENC"_a = pos_encoding,
580				"POS_ENC_DIMS_IN"_a = m_pos_encoding->input_width(),
581				"POS_ENC_OUT"_a = m_pos_encoding->generate_vec_out(),
582				"POS_ENC_N_PARAMS"_a = m_pos_encoding->n_params(),
583				"POS_ENC_PARAMS_OFFSET"_a = m_density_network->n_params() + m_rgb_network->n_params(),
584				"POS_ENC_FWD_CTX_OFFSET"_a = m_density_network->device_function_fwd_ctx_bytes() + m_rgb_network->device_function_fwd_ctx_bytes(),
585				"RGB_MLP"_a = rgb_network,
586				"RGB_MLP_IN"_a = m_rgb_network->generate_vec_in(),
587				"RGB_MLP_OUT"_a = m_rgb_network->generate_vec_out(),
588				"RGB_MLP_PARAMS_OFFSET"_a = m_density_network->n_params(),
589				"RGB_MLP_FWD_CTX_OFFSET"_a = m_density_network->device_function_fwd_ctx_bytes(),
590				"DENSITY_MLP"_a = density_network,
591				"DENSITY_MLP_DIMS_OUT"_a = m_density_network->output_width(),
592				"DIR_ENC"_a = dir_encoding,
593				"DIR_ENC_DIMS_IN"_a = m_dir_encoding->input_width(),
594				"DIR_ENC_DIMS_OUT"_a = m_dir_encoding->output_width(),
595				"DIR_ENC_N_PARAMS"_a = m_dir_encoding->n_params(),
596				"DIR_ENC_PARAMS_OFFSET"_a = m_density_network->n_params() + m_rgb_network->n_params() + m_pos_encoding->n_params(),
597				"DIR_ENC_FWD_CTX_OFFSET"_a = m_density_network->device_function_fwd_ctx_bytes() + m_rgb_network->device_function_fwd_ctx_bytes() + m_pos_encoding->device_function_fwd_ctx_bytes(),
598				"DIR_OFFSET"_a = m_dir_offset
599			);
600	
601			return fmt::format("{}{}", preamble.str(), this->generate_backward_device_function_from_body(name, body));
602		}
603	
604		uint32_t device_function_fwd_ctx_bytes() const override {
605			return
606				m_density_network->device_function_fwd_ctx_bytes() +
607				m_rgb_network->device_function_fwd_ctx_bytes() +
608				m_pos_encoding->device_function_fwd_ctx_bytes() +
609				m_dir_encoding->device_function_fwd_ctx_bytes()
610				;
611		}
612	
613		bool device_function_fwd_ctx_aligned_per_element() const override {
614			return false;
615		}
616	
617		uint32_t backward_device_function_shmem_bytes(uint32_t n_threads, GradientMode param_gradients_mode) const override {
618			return std::max(
619				std::max(
620					m_density_network->backward_device_function_shmem_bytes(n_threads, param_gradients_mode),
621					m_rgb_network->backward_device_function_shmem_bytes(n_threads, param_gradients_mode)
622				),
623				std::max(
624					m_pos_encoding->backward_device_function_shmem_bytes(n_threads, param_gradients_mode),
625					m_dir_encoding->backward_device_function_shmem_bytes(n_threads, param_gradients_mode)
626				)
627			);
628		}
629	
630		void convert_params_to_jit_layout(cudaStream_t stream, bool use_inference_params) override {
631			m_density_network->convert_params_to_jit_layout(stream, use_inference_params);
632			m_rgb_network->convert_params_to_jit_layout(stream, use_inference_params);
633			m_pos_encoding->convert_params_to_jit_layout(stream, use_inference_params);
634			m_dir_encoding->convert_params_to_jit_layout(stream, use_inference_params);
635		}
636	
637		void convert_params_from_jit_layout(cudaStream_t stream, bool use_inference_params) override {
638			m_density_network->convert_params_from_jit_layout(stream, use_inference_params);
639			m_rgb_network->convert_params_from_jit_layout(stream, use_inference_params);
640			m_pos_encoding->convert_params_from_jit_layout(stream, use_inference_params);
641			m_dir_encoding->convert_params_from_jit_layout(stream, use_inference_params);
642		}
643	
644	private:
645		std::shared_ptr<Network<T>> m_density_network;
646		std::shared_ptr<Network<T>> m_rgb_network;
647		std::shared_ptr<Encoding<T>> m_pos_encoding;
648		std::shared_ptr<Encoding<T>> m_dir_encoding;
649	
650		// Aggregates m_pos_encoding and m_density_network
651		std::shared_ptr<NetworkWithInputEncoding<T>> m_density_model;
652	
653		uint32_t m_rgb_network_input_width;
654		uint32_t m_n_pos_dims;
655		uint32_t m_n_dir_dims;
656		uint32_t m_n_extra_dims; // extra dimensions are assumed to be part of a compound encoding with dir_dims
657		uint32_t m_dir_offset;
658	
659		// // Storage of forward pass data
660		struct ForwardContext : public Context {
661			GPUMatrixDynamic<T> density_network_input;
662			GPUMatrixDynamic<T> density_network_output;
663			GPUMatrixDynamic<T> rgb_network_input;
664			GPUMatrix<T> rgb_network_output;
665	
666			std::unique_ptr<Context> pos_encoding_ctx;
667			std::unique_ptr<Context> dir_encoding_ctx;
668	
669			std::unique_ptr<Context> density_network_ctx;
670			std::unique_ptr<Context> rgb_network_ctx;
671		};
672	};
673	
674	}
